import React, { useEffect } from 'react';
import styled from 'styled-components';
import { useTheme } from '../context/ThemeContext';
import { PageWrapper, ContentContainer, Section, Header } from '../components/common/PageWrapper';
import Footer from '../components/Footer';
import AOS from 'aos';
import 'aos/dist/aos.css';

const EventsContainer = styled.div`
  height: 100%;
  background: ${props => props.theme.background};
  padding-top: 20px;
  transition: background-color 0.3s ease;
  display: flex;
  flex-direction: column;
  align-items: center;
`;

const RoadmapSection = styled.section`
  padding: 100px 0%;
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
  position: relative;
`;

const RoadmapContainer = styled.div`
  display: grid;
  width: 100%;
  grid-template-columns: 1fr 1fr; /* Two equal columns */
  gap: 0; /* Remove gap as timeline will be overlaid */
  position: relative; /* For timeline positioning */

  @media (max-width: 768px) {
    grid-template-columns: 1fr; /* Stack columns on small screens */
    gap: 0;
  }
`;

const Timeline = styled.div`
  width: 50px;
  display: flex;
  flex-direction: column;
  align-items: center;
  position: absolute;
  left: 50%;
  top: 0;
  transform: translateX(-50%);
  height: 100%;
  z-index: 2;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    bottom: 0;
    width: 4px;
    background-color: ${props => props.theme.secondary};
    left: 50%;
    transform: translateX(-50%);
  }

  @media (max-width: 768px) {
    width: 100%;
    flex-direction: row;
    justify-content: center;
    margin-bottom: 40px;
    grid-column: 1; /* Stack in the single column */

    &::before {
      width: 100%;
      height: 4px;
      top: 50%;
      bottom: auto;
      left: 0;
      transform: translateY(-50%);
    }
  }
`;

const TimelineItem = styled.div`
  position: sticky;
  bottom: 10;
  margin-top: 20px
  margin-bottom: 140px; /* Adjust this value for alignment */
  width: 50px;
  height: 50px;
  background-color: ${props => props.theme.primary};
  border-radius: 50%;
  display: flex;
  justify-content: center;
  align-items: center;
  color: ${props => props.theme.background};
  font-weight: bold;
  font-size: 1.5rem;
  z-index: 1;
  /* Adjust top based on index for alignment */
  border: 1px solid;
  transform: translateY(-50%); /* Vertically center the item */

  @media (max-width: 768px) {
    margin: 0 20px;
    top: auto; /* Reset top for mobile */
    transform: none; /* Reset transform for mobile */
  }
`;



const PhaseCard = styled.div`
  position: relative;
  background: ${props => props.theme.cardBackground};
  border: 1px solid ${props => props.theme.cardBorder};
  border-radius: 15px;
  padding: 30px;
  margin-top: 80px; /* Fixed margin-top */
  margin-bottom: 80px; /* Fixed margin-bottom */
  transition: all 0.3s ease;
  grid-column: ${props => props.align === 'left' ? 1 : 2}; /* Place in left or right column */
  justify-self: ${props => props.align === 'left' ? 'end' : 'start'}; /* Align card to the edge of its column */
  width: calc(100% - 40px); /* Ensure card takes full width minus margin */
  max-width: 450px; /* Adjusted max width for better spacing */
  max-height: fit-content;
  margin-left: ${props => props.align === 'left' ? '0' : '40px'};
  margin-right: ${props => props.align === 'left' ? '40px' : '0'};

  /* Removed conditional margins */

  @media (max-width: 768px) {
    grid-column: 1; /* Stack in the single column */
    justify-self: center; /* Center card on small screens */
    margin-bottom: 40px; /* Adjust margin for stacked layout */
    padding: 20px; /* Adjust padding for small screens */
  }

  h3 {
    color: ${props => props.theme.primary};
    margin-bottom: 15px;
    font-size: 1.8rem;
  }

  ul {
    list-style: disc;
    padding-left: 20px;

    li {
      color: ${props => props.theme.text};
      margin-bottom: 10px;
      line-height: 1.6;
    }
  }
`;

const EventGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(350px, 1fr));
  gap: 30px;
  padding: 20px;
`;

const EventCard = styled.div`
  background: ${props => props.theme.cardBackground};
  border: 1px solid ${props => props.theme.cardBorder};
  border-radius: 15px;
  overflow: hidden;
  transition: all 0.3s ease;

  img {
    width: 100%;
    height: 200px;
    object-fit: cover;
  }

  .content {
    padding: 20px;

    h3 {
      color: ${props => props.theme.primary};
      margin-bottom: 10px;
    }

    p {
      color: ${props => props.theme.text};
      margin-bottom: 15px;
    }

    .date {
      color: ${props => props.theme.secondary};
      font-size: 0.9rem;
    }
  }

  &:hover {
    transform: translateY(-5px);
    box-shadow: ${props => props.theme.shadow};
  }
`;

const Events = () => {
  const { theme } = useTheme();

  useEffect(() => {
    AOS.init({
      duration: 1000,
      once: true
    });
  }, []);

  const events = [
    {
      phase: "Phase 1",
      title: "LAUNCH & MINT",
      description: [
        "Release of 5,000 unique fatninja collectibles",
        "Website, smart contracts, and minting live",
        "Community channels (Discord, Twitter) activated"
      ]
    },
    {
      phase: "Phase 2",
      title: "SHADOW TOKEN",
      description: [
        "Staking system goes live for ninja holders",
        "Launch of $shadow utility token",
        "Begin reward distributions and utility integration"
      ]
    },
    {
      phase: "Phase 3",
      title: "GAME MECHANICS",
      description: [
        "Alpha release of the ninja battle arena",
        "Skill upgrades and rarity-based abilities",
        "Leader boards, loot, and seasonal events"
      ]
    }
  ];

  return (
    <PageWrapper theme={theme}>
      <EventsContainer theme={theme}>
        <RoadmapSection>
          <Header theme={theme}>
            <h2 data-aos="fade-up">Roadmap</h2>
          </Header>
          <RoadmapContainer>
            <Timeline theme={theme}>
              {events.map((_, index) => (
                <TimelineItem key={index} theme={theme}>
                  {index + 1}
                </TimelineItem>
              ))}
            </Timeline>
              {events.map((event, index) => (
                <PhaseCard 
                  key={index} 
                  theme={theme}
                  data-aos="fade-up"
                  data-aos-delay={100 * index}
                  align={index % 2 === 0 ? 'left' : 'right'} /* Alternate alignment */
                >
                  <h3>{event.phase}: {event.title}</h3>
                  <ul>
                    {event.description.map((item, itemIndex) => (
                      <li key={itemIndex}>{item}</li>
                    ))}
                  </ul>
                </PhaseCard>
              ))}
          </RoadmapContainer>
        </RoadmapSection>
        <Footer />
      </EventsContainer>
    </PageWrapper>
  );
};

export default Events;
